import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { type Profile, type LoyaltyCard } from '@astrolab/shared';

function App() {
  const demoProfile: Profile = {
    id: 'demo-1',
    role: 'merchant',
    email: 'demo@astrolab.app',
    created_at: new Date().toISOString(),
  };

  const demoCard: LoyaltyCard = {
    id: 'card-1',
    customer_id: 'cust-1',
    merchant_id: demoProfile.id,
    total_points: 150,
    total_stamps: 7,
    stamps_current_card: 3,
  };

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: '2rem' }}>
      <h1>AstroLab</h1>
      <p>Monorepo initialisé avec succès.</p>
      <h2>Demo Profile</h2>
      <pre>{JSON.stringify(demoProfile, null, 2)}</pre>
      <h2>Demo Loyalty Card</h2>
      <pre>{JSON.stringify(demoCard, null, 2)}</pre>
    </div>
  );
}

export default App;

