import { StatusBar } from 'expo-status-bar';
import { StyleSheet, Text, View } from 'react-native';
import { type Profile, type LoyaltyCard } from '@astrolab/shared';

export default function App() {
  const demoProfile: Profile = {
    id: 'demo-1',
    role: 'customer',
    email: 'client@astrolab.app',
    created_at: new Date().toISOString(),
  };

  const demoCard: LoyaltyCard = {
    id: 'card-1',
    customer_id: 'cust-1',
    merchant_id: 'merch-1',
    total_points: 75,
    total_stamps: 4,
    stamps_current_card: 4,
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>AstroLab</Text>
      <Text>Monorepo initialisé avec succès.</Text>
      <Text style={styles.subtitle}>Profil : {demoProfile.email}</Text>
      <Text>Points : {demoCard.total_points}</Text>
      <Text>Tampons : {demoCard.stamps_current_card}</Text>
      <StatusBar style="auto" />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
    alignItems: 'center',
    justifyContent: 'center',
    padding: 20,
  },
  title: {
    fontSize: 28,
    fontWeight: 'bold',
    marginBottom: 10,
  },
  subtitle: {
    fontSize: 16,
    fontWeight: '600',
    marginTop: 15,
    marginBottom: 5,
  },
});

